class RankVectorsByNmiCosineFusionInput(BaseModel):
    query_vector: list[float] = Field(..., description='The reference vector to rank against. Must have the same dimensionality as every vector in candidate_matrix. Values must be finite floats; NaN or Inf will be rejected.')
    candidate_matrix: list[list[float]] = Field(..., description='2-D array of candidate vectors. Each row is one candidate; columns must match the dimensionality of query_vector. Min 1 row, max 50,000 rows.')
