    nmi_bins: float = Field(None, description='Histogram bins for NMI discretization. Valid range: 2-64. Should match the value used during threshold calibration to ensure score comparability.')
    fusion_mode: str = Field(None, description="Score fusion mode: 'entropy_weighted' (default, data-driven weighting) or 'equal' (unweighted mean). Must match the fusion_mode used during threshold calibration.")


